package org.apache.commons.lang3;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Test suite for CharUtils generated by LLM pipeline.
 * Strategy: Template-Driven Constraint Sandboxing.
 */
public class LlmGeneratedCharUtilsTest {

    @Test
    public void testToChar_validString() {
        assertEquals('A', CharUtils.toChar("A"));
        assertEquals('5', CharUtils.toChar("5"));
    }

    @Test
    public void testToChar_CharacterObject() {
        Character character = Character.valueOf('X');
        assertEquals('X', CharUtils.toChar(character));
    }

    @Test
    public void testToIntValue_validChar() {
        assertEquals(5, CharUtils.toIntValue('5'));
        assertEquals(0, CharUtils.toIntValue('0'));
    }

    @Test
    public void testIsAsciiNumeric() {
        assertTrue(CharUtils.isAsciiNumeric('7'));
        assertFalse(CharUtils.isAsciiNumeric('A'));
        assertFalse(CharUtils.isAsciiNumeric('-'));
    }

    @Test
    public void testIsAsciiAlpha() {
        assertTrue(CharUtils.isAsciiAlpha('b'));
        assertTrue(CharUtils.isAsciiAlpha('Z'));
        assertFalse(CharUtils.isAsciiAlpha('3'));
    }
}